import osimport sysimport winregimport ctypesdef is_admin():    # проверка на запуск с правами администратора    try:        return ctypes.windll.shell32.IsUserAnAdmin()    except:        return Falsedef add_context_menu():    # узнаём где лежит пайтон    python_exe = sys.executable    # Получаем абсолютный путь к папке, где лежит этот скрипт    current_dir = os.path.abspath(os.path.dirname(__file__))    main_script = os.path.join(current_dir, "main.py")    server_script = os.path.join(current_dir, "main_for_server.py")    print(f"Путь к Python: {python_exe}")    print(f"Путь к проектам: {current_dir}\n")    try:        # --- Добавляем кнопку ОТПРАВКИ (для файлов) ---        key_path_send = r"*\shell\SendViaLANDrop"        with winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, key_path_send) as key:            winreg.SetValueEx(key, "", 0, winreg.REG_SZ, "Отправить через LANDrop")            winreg.SetValueEx(key, "Icon", 0, winreg.REG_SZ, "imageres.dll,-1004")        with winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, key_path_send + r"\command") as key:            # Формируем команду запуска            command_send = f'"{python_exe}" "{main_script}" "%1"'            winreg.SetValueEx(key, "", 0, winreg.REG_SZ, command_send)        print("✅ Успешно добавлено меню отправки!")        # --- Добавляем кнопку ОТПРАВКИ (для ПАПОК) ---        # Меняем Directory на Folder — это работает надежнее        key_path_send_dir = r"Folder\shell\SendDirViaLANDrop"        with winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, key_path_send_dir) as key:            winreg.SetValueEx(key, "", 0, winreg.REG_SZ, "Отправить папку через LANDrop")            winreg.SetValueEx(key, "Icon", 0, winreg.REG_SZ, "imageres.dll,-1004")        with winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, key_path_send_dir + r"\command") as key:            # %1 передаст абсолютный путь к выделенной папке            command_send_dir = f'"{python_exe}" "{main_script}" "%1"'            winreg.SetValueEx(key, "", 0, winreg.REG_SZ, command_send_dir)        print("✅ Успешно добавлено меню отправки для папок!")        # --- Добавляем кнопку ПРИЕМКИ (для папок) ---        key_path_recv = r"Directory\Background\shell\ReceiveViaLANDrop"        with winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, key_path_recv) as key:            winreg.SetValueEx(key, "", 0, winreg.REG_SZ, "Принять файл сюда (LANDrop)")            winreg.SetValueEx(key, "Icon", 0, winreg.REG_SZ, "imageres.dll,-1003")        with winreg.CreateKey(winreg.HKEY_CLASSES_ROOT, key_path_recv + r"\command") as key:            # Формируем команду запуска            command_recv = f'"{python_exe}" "{server_script}" "%V"'            winreg.SetValueEx(key, "", 0, winreg.REG_SZ, command_recv)        print("✅ Успешно добавлено меню приемки!")    except Exception as e:        print(f"❌ Ошибка при записи в реестр: {e}")        print("Убедитесь, что антивирус не блокирует изменение реестра.")    input("\nУстановка завершена. Нажмите Enter для выхода...")if __name__ == "__main__":    if is_admin():        add_context_menu()    else:        print("Запрашиваем права администратора...")        # Перезапускаем этот же скрипт, но с запросом прав админа (появится окошко Windows)        ctypes.windll.shell32.ShellExecuteW(None, "runas", sys.executable, f'"{__file__}"', None, 1)